import{_ as s,o as i,c as o,a6 as r}from"./chunks/framework.CgU7tkAh.js";const m=JSON.parse('{"title":"Users","description":"","frontmatter":{},"headers":[],"relativePath":"admin/acl/users.md","filePath":"admin/acl/users.md"}'),t={name:"admin/acl/users.md"};function a(n,e,l,d,c,p){return i(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="users" tabindex="-1">Users <a class="header-anchor" href="#users" aria-label="Permalink to “Users”">​</a></h1><p>Users resource defines primary user records.</p><h2 id="properties" tabindex="-1">Properties <a class="header-anchor" href="#properties" aria-label="Permalink to “Properties”">​</a></h2><ul><li><p><code>Name</code> - User name</p></li><li><p><code>Email</code> - Valid email address, allows login to admin tool and restore password functionality</p></li><li><p><code>Phone</code> - Phone number</p></li><li><p><code>Assigned roles</code> - Roles user is assigned with. Grants permissions based on the role settings</p></li><li><p><code>Assigned permissions</code> - Permissions user is <strong>directly</strong> assigned with (not through the <code>role</code>)</p></li></ul><div class="tip custom-block"><p class="custom-block-title">Survey-based permissions</p><p>When setting up survey-related users, it&#39;s better to handle permissions through Survey UI. For setting up system users, it&#39;s better to use roles as there are usually more people that will require similar set of permissions and it&#39;s then easier to manage through role rather than individually through each user/permission.</p></div><ul><li><p><code>Multi-factor authentication</code> - Turns <code>on</code> / <code>off</code> multi-factor authentication for specific user. This firstly needs to be enabled on system level and correctly configured with 3rd party provider.</p></li><li><p><code>Verified</code> - User verification status. Verified user can log in to admin tool and use the system. Unverified user cannot log in to admin tool and is treated as non-existing user in the system.</p></li><li><p><code>Disabled</code> - User disabled status. Disabled user cannot log in to admin tool and is treated as non-existing user in the system.</p></li><li><p><code>Email notifications</code> - To be clarified</p></li><li><p><code>SMS notifications</code> - To be clarified</p></li></ul>',6)])])}const h=s(t,[["render",a]]);export{m as __pageData,h as default};
